import { IMessageComposer } from '@nitrots/nitro-renderer';

export class BlackJackBetComposer implements IMessageComposer<unknown[]> {
    constructor(private _tableId: number, private _amount: number) {}
    public getMessageArray() {
        return [this._tableId, this._amount];
    }
    public dispose(): void {}
    public get disposed(): boolean {
        return false;
    }
}
